+    #[test]
+    fn test_paginator_next_prev_bounded(
+        total in 1usize..100,
+        steps in 0usize..200,
+    ) {
+        let mut p = Paginator::new().total_pages(total);
+
+        for _ in 0..steps {
+            p.next_page();
+        }
+        prop_assert!(p.page() < total);
